    // ==================== WebView Clients ====================

    private class HybridWebViewClient extends WebViewClient {

        @Override
        public void onPageStarted(WebView view, String url, Bitmap favicon) {
            super.onPageStarted(view, url, favicon);
            progressBar.setVisibility(View.VISIBLE);
        }

        @Override
        public void onPageFinished(WebView view, String url) {
            super.onPageFinished(view, url);
            progressBar.setVisibility(View.GONE);
            injectBridgeHelperScript();
        }

        @Override
        public void onReceivedError(WebView view, WebResourceRequest request, WebResourceError error) {
            super.onReceivedError(view, request, error);
            if (request.isForMainFrame()) {
                Log.e(TAG, "WebView error: " + error.getDescription());
                loadErrorPage(view);
            }
        }

        @Override
        public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();

            // Handle external links
            if (!url.startsWith(WEB_URL) && !url.startsWith("https://your-mobile-website.com")) {
                // Handle specific schemes
                if (url.startsWith("tel:") || url.startsWith("mailto:") ||
                        url.startsWith("sms:") || url.startsWith("whatsapp:")) {
                    Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                    startActivity(intent);
                    return true;
                }

                // Handle intent:// URLs
                if (url.startsWith("intent://")) {
                    try {
                        Intent intent = Intent.parseUri(url, Intent.URI_INTENT_SCHEME);
                        if (intent.resolveActivity(getPackageManager()) != null) {
                            startActivity(intent);
                        }
                    } catch (Exception e) {
                        Log.e(TAG, "Error handling intent URL", e);
                    }
                    return true;
                }

                // Open other external URLs in browser
                Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                startActivity(intent);
                return true;
            }

            return false;
        }
    }

    private class HybridWebChromeClient extends WebChromeClient {

        @Override
        public void onProgressChanged(WebView view, int newProgress) {
            progressBar.setProgress(newProgress);
            if (newProgress == 100) {
                progressBar.setVisibility(View.GONE);
            }
        }

        @Override
        public boolean onConsoleMessage(ConsoleMessage consoleMessage) {
            Log.d(TAG, "Console: " + consoleMessage.message() +
                    " -- From line " + consoleMessage.lineNumber() +
                    " of " + consoleMessage.sourceId());
            return true;
        }

        @Override
        public void onGeolocationPermissionsShowPrompt(String origin,
                                                        GeolocationPermissions.Callback callback) {
            if (checkLocationPermission()) {
                callback.invoke(origin, true, false);
            } else {
                callback.invoke(origin, false, false);
            }
        }

        @Override
        public boolean onShowFileChooser(WebView webView, ValueCallback<Uri[]> filePathCallback,
                                         FileChooserParams fileChooserParams) {
            if (fileUploadCallback != null) {
                fileUploadCallback.onReceiveValue(null);
            }
            fileUploadCallback = filePathCallback;

            String[] acceptTypes = fileChooserParams.getAcceptTypes();
            boolean captureEnabled = fileChooserParams.isCaptureEnabled();

            if (captureEnabled && acceptTypes.length > 0 && acceptTypes[0].startsWith("image")) {
                if (checkCameraPermission()) {
                    launchCamera();
                }
            } else {
                Intent intent = fileChooserParams.createIntent();
                fileChooserLauncher.launch(intent);
            }

            return true;
        }
    }

    // ==================== Camera Functions ====================

    private boolean checkCameraPermission() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                != PackageManager.PERMISSION_GRANTED) {
            ActivityCompat.requestPermissions(this,
                    new String[]{Manifest.permission.CAMERA}, PERMISSION_REQUEST_CAMERA);
            return false;
        }
        return true;
    }

    private void launchCamera() {
        Intent cameraIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (cameraIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = createImageFile();
            if (photoFile != null) {
                cameraImageUri = FileProvider.getUriForFile(this,
                        getPackageName() + ".fileprovider", photoFile);
                cameraIntent.putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri);
                cameraLauncher.launch(cameraIntent);
            }
        }
    }

    private File createImageFile() {
        try {
            String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault())
                    .format(new Date());
            String imageFileName = "IMG_" + timeStamp + "_";
            File storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES);
            return File.createTempFile(imageFileName, ".jpg", storageDir);
        } catch (IOException e) {
            Log.e(TAG, "Error creating image file", e);
            return null;
        }
    }

    // ==================== Location Functions ====================

    private boolean checkLocationPermission() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION)
                != PackageManager.PERMISSION_GRANTED) {
            ActivityCompat.requestPermissions(this,
                    new String[]{
                            Manifest.permission.ACCESS_FINE_LOCATION,
                            Manifest.permission.ACCESS_COARSE_LOCATION
                    }, PERMISSION_REQUEST_LOCATION);
            return false;
        }
        return true;
    }

    @SuppressLint("MissingPermission")
    private void fetchLocation() {
        CancellationTokenSource cancellationTokenSource = new CancellationTokenSource();
        fusedLocationClient.getCurrentLocation(Priority.PRIORITY_HIGH_ACCURACY,
                        cancellationTokenSource.getToken())
                .addOnSuccessListener(this, location -> {
                    if (location != null) {
                        sendLocationToWeb(location);
                    } else {
                        // Fallback to last known location
                        fusedLocationClient.getLastLocation()
                                .addOnSuccessListener(this, lastLocation -> {
                                    if (lastLocation != null) {
                                        sendLocationToWeb(lastLocation);
                                    } else {
                                        sendLocationErrorToWeb("Unable to get location");
                                    }
                                });
                    }
                })
                .addOnFailureListener(this, e -> {
                    sendLocationErrorToWeb(e.getMessage());
                });
    }

    private void sendLocationToWeb(Location location) {
        String callbackName = pendingLocationCallbackName != null ?
                pendingLocationCallbackName : "onLocationReceived";
        JSONObject locationData = new JSONObject();
        try {
            locationData.put("latitude", location.getLatitude());
            locationData.put("longitude", location.getLongitude());
            locationData.put("accuracy", location.getAccuracy());
            locationData.put("altitude", location.getAltitude());
            locationData.put("speed", location.getSpeed());
            locationData.put("timestamp", location.getTime());
        } catch (JSONException e) {
            Log.e(TAG, "Error creating location JSON", e);
        }
        String js = "javascript:window.NativeBridge." + callbackName +
                "('" + locationData.toString() + "')";
        runOnUiThread(() -> webView.evaluateJavascript(js, null));
    }

    private void sendLocationErrorToWeb(String error) {
        String js = "javascript:window.NativeBridge.onLocationError('" + error + "')";
        runOnUiThread(() -> webView.evaluateJavascript(js, null));
    }

    // ==================== Payment Functions ====================

    private void processPayment(String paymentDataJson) {
        try {
            JSONObject paymentData = new JSONObject(paymentDataJson);
            String amount = paymentData.optString("amount", "0");
            String currency = paymentData.optString("currency", "USD");
            String description = paymentData.optString("description", "Payment");
            String orderId = paymentData.optString("orderId", "");

            Log.d(TAG, "Processing payment: " + amount + " " + currency + " for " + description);

            // TODO: Integrate with actual payment SDK (Google Pay, Stripe, etc.)
            // Example: Launch Google Pay
            // For now, simulate a payment result

            // Simulate payment processing
            new android.os.Handler(getMainLooper()).postDelayed(() -> {
                JSONObject result = new JSONObject();
                try {
                    result.put("status", "success");
                    result.put("transactionId", "TXN_" + System.currentTimeMillis());
                    result.put("orderId", orderId);
                    result.put("amount", amount);
                    result.put("currency", currency);
                } catch (JSONException e) {
                    Log.e(TAG, "Error creating payment result", e);
                }
                webView.evaluateJavascript(
                        "javascript:window.NativeBridge.onPaymentResult('" +
                                result.toString() + "')", null);
            }, 2000);

        } catch (JSONException e) {
            Log.e(TAG, "Error parsing payment data", e);
            webView.evaluateJavascript(
                    "javascript:window.NativeBridge.onPaymentError('Invalid payment data')", null);
        }
    }

    // ==================== Helper Functions ====================

    private void injectBridgeHelperScript() {
        String bridgeScript = "javascript:(function() {" +
                "  if (window.NativeBridge) return;" +
                "  window.NativeBridge = {" +
                "    callbacks: {}," +
                "    onLocationReceived: function(data) {" +
                "      var parsed = JSON.parse(data);" +
                "      if (this.callbacks.location) {" +
                "        this.callbacks.location(parsed);" +
                "        delete this.callbacks.location;" +
                "      }" +
                "      document.dispatchEvent(new CustomEvent('nativeLocation', {detail: parsed}));" +
                "    }," +
                "    onLocationError: function(error) {" +
                "      if (this.callbacks.locationError) {" +
                "        this.callbacks.locationError(error);" +
                "        delete this.callbacks.locationError;" +
                "      }" +
                "      document.dispatchEvent(new CustomEvent('nativeLocationError', {detail: error}));" +
                "    }," +
                "    onCameraResult: function(uri) {" +
                "      if (this.callbacks.camera) {" +
                "        this.callbacks.camera(uri);" +
                "        delete this.callbacks.camera;" +
                "      }" +
                "      document.dispatchEvent(new CustomEvent('nativeCameraResult', {detail: uri}));" +
                "    }," +
                "    onCameraError: function(error) {" +
                "      if (this.callbacks.cameraError) {" +
                "        this.callbacks.cameraError(error);" +
                "        delete this.callbacks.cameraError;" +
                "      }" +
                "      document.dispatchEvent(new CustomEvent('nativeCameraError', {detail: error}));" +
                "    }," +
                "    onPaymentResult: function(data) {" +
                "      var parsed = JSON.parse(data);" +
                "      if (this.callbacks.payment) {" +
                "        this.callbacks.payment(parsed);" +
                "        delete this.callbacks.payment;" +
                "      }" +
                "      document.dispatchEvent(new CustomEvent('nativePaymentResult', {detail: parsed}));" +
                "    }," +
                "    onPaymentError: function(error) {" +
                "      if (this.callbacks.paymentError) {" +
                "        this.callbacks.paymentError(error);" +
                "        delete this.callbacks.paymentError;" +
                "      }" +
                "      document.dispatchEvent(new CustomEvent('nativePaymentError', {detail: error}));" +
                "    }," +
                "    requestLocationAsync: function() {" +
                "      return new Promise(function(resolve, reject) {" +
                "        window.NativeBridge.callbacks.location = resolve;" +
                "        window.NativeBridge.callbacks.locationError = reject;" +
                "        AndroidBridge.getLocation();" +
                "      });" +
                "    }," +
                "    openCameraAsync: function() {" +
                "      return new Promise(function(resolve, reject) {" +
                "        window.NativeBridge.callbacks.camera = resolve;" +
                "        window.NativeBridge.callbacks.cameraError = reject;" +
                "        AndroidBridge.openCamera();" +
                "      });" +
                "    }," +
                "    makePaymentAsync: function(paymentData) {" +
                "      return new Promise(function(resolve, reject) {" +
                "        window.NativeBridge.callbacks.payment = resolve;" +
                "        window.NativeBridge.callbacks.paymentError = reject;" +
                "        AndroidBridge.initiatePayment(JSON.stringify(paymentData));" +
                "      });" +
                "    }" +
                "  };" +
                "  document.dispatchEvent(new Event('nativeBridgeReady'));" +
                "  console.log('NativeBridge initialized');" +
                "})();";

        webView.evaluateJavascript(bridgeScript, null);
    }

